import numpy as np

def solve_jacobi(A: np.ndarray, b: np.ndarray, n: int) -> list:
    rows = A.shape[0]
    x = np.zeros(rows)

    # Decompose A = D + R where D is diagonal and R is the remainder
    D_inv = 1.0 / np.diag(A)          # element-wise inverse of diagonal
    R = A - np.diag(np.diag(A))       # off-diagonal part

    for _ in range(n):
        x = np.round(D_inv * (b - R @ x), 4)

    return x.tolist()
